         const PAGE_SIZE = 50;

+        // === Memory Management ===
+
+        // Memory limits and tracking
+        const MEMORY_CONFIG = {
+            // Warn when heap usage exceeds this percentage
+            warnThreshold: 0.7,  // 70%
+            // Fail operations when exceeds this
+            failThreshold: 0.85, // 85%
+            // Maximum file size to load into memory (100MB default, can be lower on mobile)
+            maxFileSize: 100 * 1024 * 1024,
+            // Minimum free memory required for operations (50MB)
+            minFreeMemory: 50 * 1024 * 1024,
+        };
+
+        // Get current memory usage (Chrome-only, estimate for others)
+        function getMemoryInfo() {
+            // Chrome exposes detailed memory info
+            if (performance.memory) {
+                return {
+                    used: performance.memory.usedJSHeapSize,
+                    total: performance.memory.totalJSHeapSize,
+                    limit: performance.memory.jsHeapSizeLimit,
+                    available: performance.memory.jsHeapSizeLimit - performance.memory.usedJSHeapSize,
+                    supported: true
+                };
+            }
+            // Fallback: estimate based on typical browser limits
+            // Most browsers have ~2GB heap limit, mobile ~512MB
+            const isMobile = /iPhone|iPad|iPod|Android/i.test(navigator.userAgent);
+            const estimatedLimit = isMobile ? 512 * 1024 * 1024 : 2 * 1024 * 1024 * 1024;
+            return {
+                used: 0,
+                total: 0,
+                limit: estimatedLimit,
+                available: estimatedLimit,
+                supported: false
+            };
+        }
+
+        // Check if we have enough memory for an operation
+        function checkMemoryForOperation(requiredBytes, operationName) {
+            const mem = getMemoryInfo();
+
+            // Check file size limit
+            if (requiredBytes > MEMORY_CONFIG.maxFileSize) {
+                const maxMB = (MEMORY_CONFIG.maxFileSize / 1024 / 1024).toFixed(0);
+                const reqMB = (requiredBytes / 1024 / 1024).toFixed(1);
+                throw new Error(
+                    `File too large: ${reqMB}MB exceeds ${maxMB}MB limit. ` +
+                    `Use smaller files or chunked loading.`
+                );
+            }
+
+            if (mem.supported) {
+                // Check heap usage percentage
+                const usagePercent = mem.used / mem.limit;
+                if (usagePercent > MEMORY_CONFIG.failThreshold) {
+                    throw new Error(
+                        `Memory limit reached (${(usagePercent * 100).toFixed(0)}% used). ` +
+                        `Clear some tables or refresh the page.`
+                    );
+                }
+
+                // Check if enough free memory
+                if (mem.available < requiredBytes + MEMORY_CONFIG.minFreeMemory) {
+                    const availMB = (mem.available / 1024 / 1024).toFixed(0);
+                    const reqMB = (requiredBytes / 1024 / 1024).toFixed(1);
+                    throw new Error(
+                        `Not enough memory for ${operationName}: need ${reqMB}MB, only ${availMB}MB available. ` +
+                        `Clear some tables first.`
+                    );
+                }
+
+                // Warn if approaching limit
+                if (usagePercent > MEMORY_CONFIG.warnThreshold) {
+                    console.warn(`Memory warning: ${(usagePercent * 100).toFixed(0)}% heap used`);
+                    showStatus(`⚠️ Memory usage high (${(usagePercent * 100).toFixed(0)}%)`, 'warning');
+                }
+            }
+
+            return true;
+        }
+
+        // Update memory display in UI
+        function updateMemoryDisplay() {
+            const mem = getMemoryInfo();
+            const memUsedEl = document.getElementById('memory-used');
+            const memLimitEl = document.getElementById('memory-limit');
+            const memBarEl = document.getElementById('memory-bar-fill');
+
+            if (memUsedEl && mem.supported) {
+                memUsedEl.textContent = formatBytes(mem.used);
+                memLimitEl.textContent = formatBytes(mem.limit);
+
+                const percent = (mem.used / mem.limit) * 100;
+                memBarEl.style.width = `${Math.min(percent, 100)}%`;
+
+                // Color based on usage
+                if (percent > MEMORY_CONFIG.failThreshold * 100) {
+                    memBarEl.style.background = '#ef4444'; // red
+                } else if (percent > MEMORY_CONFIG.warnThreshold * 100) {
+                    memBarEl.style.background = '#f59e0b'; // yellow
+                } else {
+                    memBarEl.style.background = '#10b981'; // green
+                }
+            } else if (memUsedEl) {
+                memUsedEl.textContent = 'N/A';
+                memLimitEl.textContent = '(Chrome only)';
+                memBarEl.style.width = '0%';
+            }
+        }
+
+        // Periodically update memory display
+        setInterval(updateMemoryDisplay, 2000);
+
+        // === Storage Management Functions ===
+
+        // OPFS support detection - use package's opfsStorage
+        let opfsSupported = false;
+        async function checkOPFSSupport() {
+            // Use the package's OPFSStorage which has proper detection
+            opfsSupported = await opfsStorage.isSupported();
+            return opfsSupported;
+        }
+
+        // Track if user has unsaved data (for exit prompt)
+        let hasUnsavedData = false;
+
+        // Warn user before leaving if they have local data
+        window.addEventListener('beforeunload', (e) => {
+            if (hasUnsavedData && tablesRegistry.size > 0) {
+                e.preventDefault();
+                e.returnValue = 'You have locally cached data. Are you sure you want to leave?';
+                return e.returnValue;
+            }
+        });
+
+        function formatBytes(bytes) {
+            if (bytes === 0) return '0 B';
+            const k = 1024;
+            const sizes = ['B', 'KB', 'MB', 'GB'];
+            const i = Math.floor(Math.log(bytes) / Math.log(k));
+            return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
+        }
+
+        function toggleStoragePanel() {
+            const panel = document.getElementById('storage-panel');
+            panel.classList.toggle('collapsed');
+            if (!panel.classList.contains('collapsed')) {
+                refreshStorageStats();
+            }
+        }
+
+        function updateStoragePanelSupport() {
+            const panel = document.getElementById('storage-panel');
+            const indicator = document.getElementById('opfs-support-indicator');
+            if (!opfsSupported) {
+                panel.classList.add('unsupported');
+                if (indicator) {
+                    indicator.innerHTML = '<span class="opfs-unsupported">OPFS not supported</span>';
+                }
+            }
+        }
+
+        async function refreshStorageStats() {
+            if (!opfsSupported) {
+                document.getElementById('storage-used').textContent = 'N/A';
+                document.getElementById('storage-files-count').textContent = '-';
+                document.getElementById('storage-quota').textContent = 'N/A';
+                document.getElementById('storage-files-list').innerHTML =
+                    '<div class="storage-empty">OPFS not supported in this browser. Files will work in memory only.</div>';
+                return;
+            }
+
+            try {
+                // Use package's opfsStorage for stats
+                const stats = await opfsStorage.getStats();
+                document.getElementById('storage-used').textContent = formatBytes(stats.totalSize);
+                document.getElementById('storage-files-count').textContent = stats.fileCount;
+
+                // Get storage quota
+                if (navigator.storage && navigator.storage.estimate) {
+                    const estimate = await navigator.storage.estimate();
+                    const quota = estimate.quota || 0;
+                    document.getElementById('storage-quota').textContent = formatBytes(quota - stats.totalSize);
+                }
+
+                // Get file list using package API
+                const files = await opfsStorage.listFiles();
+
+                // Update hasUnsavedData flag
+                hasUnsavedData = files.length > 0;
+
+                // Render file list
+                const listEl = document.getElementById('storage-files-list');
+                if (files.length === 0) {
+                    listEl.innerHTML = '<div class="storage-empty">No files cached locally</div>';
+                } else {
+                    listEl.innerHTML = files.map(f => `
+                        <div class="storage-file-item" data-file="${f.name}">
+                            <div class="storage-file-info">
+                                <svg class="storage-file-icon" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
+                                    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
+                                    <polyline points="14,2 14,8 20,8"/>
+                                </svg>
+                                <span class="storage-file-name">${f.name}</span>
+                                <span class="storage-file-size">${formatBytes(f.size)}</span>
+                            </div>
+                            <button class="storage-file-delete" onclick="deleteStorageFile('${f.name}')" title="Delete">×</button>
+                        </div>
+                    `).join('');
+                }
+            } catch (e) {
+                console.warn('Failed to refresh storage stats:', e);
+            }
+        }
+
+        async function deleteStorageFile(fileName) {
+            if (!opfsSupported) return;
+            if (!confirm(`Delete "${fileName}" from local storage?`)) return;
+            try {
+                // Use package's opfsStorage
+                await opfsStorage.delete(fileName);
+
+                // Also remove from tables registry if it exists
+                const tableName = fileName.replace(/\.lance$/, '');
+                if (tablesRegistry.has(tableName)) {
+                    unregisterTable(tableName);
+                }
+
+                refreshStorageStats();
+                showStatus(`Deleted "${fileName}"`, 'success');
+            } catch (e) {
+                showStatus(`Failed to delete: ${e.message}`, 'error');
+            }
+        }
+
+        async function clearAllStorage() {
+            if (!opfsSupported) {
+                showStatus('OPFS not supported', 'error');
+                return;
+            }
+            if (!confirm('Clear all locally cached files? This cannot be undone.')) return;
+            try {
+                // Use package's opfsStorage
+                const count = await opfsStorage.clearAll();
+
+                // Clear tables registry for local tables
+                for (const [name, info] of tablesRegistry) {
+                    if (info.type === 'local') {
+                        tablesRegistry.delete(name);
+                    }
+                }
+
+                renderTablesUI();
+                refreshStorageStats();
+                hasUnsavedData = false;
+                showStatus(`Cleared ${count} files from local storage`, 'success');
+            } catch (e) {
+                showStatus(`Failed to clear storage: ${e.message}`, 'error');
+            }
+        }
+
+        // Clear entire session - OPFS + in-memory tables + reset UI
+        async function clearSession() {
+            if (!confirm('Clear your session? This will remove all loaded tables and cached files.')) return;
+
+            try {
+                // Clear OPFS if supported using package API
+                if (opfsSupported) {
+                    await opfsStorage.clearAll();
+                }
+
+                // Clear in-memory tables
+                for (const [name, info] of tablesRegistry) {
+                    if (info?.dataset?.close) {
+                        try { info.dataset.close(); } catch (e) {}
+                    }
+                }
+                tablesRegistry.clear();
+
+                // Reset UI state
+                $currentFile.set(null);
+                $columnTypes.set([]);
+                $totalBytesDownloaded.set(0);
+                $totalRequests.set(0);
+                Alpine.store('app').opfsWritten = 0;
+                hasUnsavedData = false;
+
+                // Clear results
+                document.getElementById('results-table-body').innerHTML = '';
+                document.getElementById('results-table-header').innerHTML = '';
+
+                renderTablesUI();
+                refreshStorageStats();
+                showStatus('Session cleared', 'success');
+            } catch (e) {
+                showStatus(`Failed to clear session: ${e.message}`, 'error');
+            }
+        }
