+    static encodeVarint(value) {
+        const bytes = [];
+        let v = typeof value === 'bigint' ? value : BigInt(value);
+        while (v > 0x7fn) {
+            bytes.push(Number(v & 0x7fn) | 0x80);
+            v >>= 7n;
+        }
+        bytes.push(Number(v));
+        return new Uint8Array(bytes);
+    }
